#' Clinical Scoring System Generator
#'
#' Builds clinical integer-point scoring systems from regression models using
#' three published methods (Sullivan/D'Agostino, Schneeweiss, Beta10).
#' Supports logistic, Cox, linear, and ordinal regression with automatic
#' variable categorization, calibration, discrimination, nomogram generation,
#' and TRIPOD compliance.
#' 
#'
#' @examples
#' \donttest{
#' clinicalscore(data = data, outcome = "diagnosis",
#'     outcomeLevel = "malignant", explanatory = vars(age, grade, ki67),
#'     modelType = "logistic", scoringMethod = "compare")
#'}
#' @param data .
#' @param modelType .
#' @param outcome .
#' @param outcomeLevel .
#' @param elapsedtime .
#' @param explanatory .
#' @param autoCategorize Automatically convert continuous predictors into
#'   categories for integer-point assignment. If disabled, continuous predictors
#'   contribute points based on above/below median.
#' @param categorizeMethod .
#' @param customBreaks Comma-separated cutpoints for manual categorization.
#'   Example: "3,10,20" for Ki-67 would create G1/G2a/G2b/G3.
#' @param scoringMethod .
#' @param maxPoints .
#' @param bootstrapValidation .
#' @param bootstrapN .
#' @param scoreLookup .
#' @param showNomogram .
#' @param showCalibration .
#' @param calibrationGroups .
#' @param showDiscrimination .
#' @param showDecisionCurve .
#' @param showTRIPOD .
#' @param suitabilityCheck .
#' @param showSummary .
#' @param showExplanations .
#' @param random_seed .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$todo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$suitabilityReport} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$modelSummary} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coefficients} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$scoringTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$methodComparison} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$scoringPerformance} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$lookupTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$discriminationTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$validationTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$calibrationPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$nomogramPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$scoreDistPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$decisionCurveTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$decisionCurvePlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$tripodChecklist} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$summaryText} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$explanations} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$modelSummary$asDF}
#'
#' \code{as.data.frame(results$modelSummary)}
#'
#' @export
clinicalscore <- function(
    data,
    modelType = "logistic",
    outcome,
    outcomeLevel,
    elapsedtime = NULL,
    explanatory,
    autoCategorize = TRUE,
    categorizeMethod = "median",
    customBreaks = "",
    scoringMethod = "schneeweiss",
    maxPoints = 10,
    bootstrapValidation = FALSE,
    bootstrapN = 200,
    scoreLookup = TRUE,
    showNomogram = TRUE,
    showCalibration = TRUE,
    calibrationGroups = 4,
    showDiscrimination = TRUE,
    showDecisionCurve = FALSE,
    showTRIPOD = FALSE,
    suitabilityCheck = TRUE,
    showSummary = FALSE,
    showExplanations = FALSE,
    random_seed = 42) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("clinicalscore requires jmvcore to be installed (restart may be required)")

    if ( ! missing(outcome)) outcome <- jmvcore::resolveQuo(jmvcore::enquo(outcome))
    if ( ! missing(elapsedtime)) elapsedtime <- jmvcore::resolveQuo(jmvcore::enquo(elapsedtime))
    if ( ! missing(explanatory)) explanatory <- jmvcore::resolveQuo(jmvcore::enquo(explanatory))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(outcome), outcome, NULL),
            `if`( ! missing(elapsedtime), elapsedtime, NULL),
            `if`( ! missing(explanatory), explanatory, NULL))


    options <- clinicalscoreOptions$new(
        modelType = modelType,
        outcome = outcome,
        outcomeLevel = outcomeLevel,
        elapsedtime = elapsedtime,
        explanatory = explanatory,
        autoCategorize = autoCategorize,
        categorizeMethod = categorizeMethod,
        customBreaks = customBreaks,
        scoringMethod = scoringMethod,
        maxPoints = maxPoints,
        bootstrapValidation = bootstrapValidation,
        bootstrapN = bootstrapN,
        scoreLookup = scoreLookup,
        showNomogram = showNomogram,
        showCalibration = showCalibration,
        calibrationGroups = calibrationGroups,
        showDiscrimination = showDiscrimination,
        showDecisionCurve = showDecisionCurve,
        showTRIPOD = showTRIPOD,
        suitabilityCheck = suitabilityCheck,
        showSummary = showSummary,
        showExplanations = showExplanations,
        random_seed = random_seed)

    analysis <- clinicalscoreClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

